class Solution {
public:
    void push(int x) {
        stack.push_back(x);
    }

    int pop() {
        if (stack.empty()) {
            return -1;
        }
        int x = stack.back();
        stack.pop_back();
        return x;
    }

    int topElement() {
        if (stack.empty()) {
            return -1;
        }
        return stack.back();
    }

    int empty() {
        return stack.empty();
    }

    vector<int> stack;
};

